CREATE TABLE building(full_id VARCHAR, osm_id VARCHAR, osm_type VARCHAR, building VARCHAR, geom GEOMETRY);
CREATE TABLE cities(id BIGINT, "name" VARCHAR, geom GEOMETRY);
CREATE TABLE cities_population("name" VARCHAR, pop INTEGER);
CREATE TABLE highway(full_id VARCHAR, osm_id VARCHAR, osm_type VARCHAR, highway VARCHAR, geom GEOMETRY);
CREATE TABLE "table-test"(geom GEOMETRY);
CREATE TABLE table_no_geom(id INTEGER, "text" VARCHAR);
CREATE TABLE table_with_column_space(id BIGINT, "The Name" VARCHAR, geom GEOMETRY);
CREATE TABLE table_with_float(id BIGINT, test_float FLOAT, geom GEOMETRY);
CREATE TABLE table_with_primary_key(id INTEGER PRIMARY KEY, j VARCHAR, geom GEOMETRY);
CREATE TABLE test_multi(id BIGINT, num INTEGER, "text" VARCHAR, "float" DOUBLE, "yes" BOOLEAN, geom GEOMETRY);
CREATE VIEW marseille AS SELECT 'toto' AS toto, * FROM cities WHERE ("name" = 'Marseille');










CREATE SCHEMA data_schema;
CREATE TABLE data_schema.geodata(id INTEGER PRIMARY KEY, text VARCHAR, geom GEOMETRY);
